sql:
SELECT * 
FROM games 
WHERE game_id = 'desired_game_id';

SELECT name, series, popularity_score
FROM games
WHERE series = '19XX' AND popularity_score > (SELECT AVG(popularity_score) FROM games);

external_knowledge:
- "ocean of reviews" is a metaphor for a large collection of reviews;
- "surface the pearls of insight" refers to extracting valuable and insightful comments or reviews;
- "from the most recent to the oldest" means the reviews should be sorted such that the latest reviews are shown first.

sql:
SELECT games.name, platforms.platform_name
FROM games
JOIN platforms ON games.platform = platforms.platform_name;

SELECT name, popularity_score AS avg_popularity_score
FROM games
WHERE popularity_score > (SELECT AVG(popularity_score) FROM games);

external_knowledge:
- 'reached adulthood' refers to age >= 18 in the metaphorical context, but not relevant here; 
- 'original form' indicates that the game is not an alternative version (alternative = 0); 
- 'stars shine brightest' metaphorically refers to the games' popularity score being in descending order.

sql:
SELECT name
FROM games
WHERE year > 1980 AND series = '19XX';

SELECT name 
FROM games 
WHERE platform = "Capcom CPS-0";

SELECT attribute_value
FROM game_attributes
WHERE game_id = 1 AND attribute_name = 'linebreak1';

SELECT platform_attribute_name, platform_attribute_value
FROM game_platform_attributes
WHERE game_id = 0;
